// Scoring du lead basé sur les réponses du formulaire
const data = $input.first().json;

let score = 0;

// Critère 1 : Ville cible (max 20 points)
const targetCities = ['paris', 'lyon', 'marseille', 'bordeaux', 'nice', 'toulouse', 'nantes', 'strasbourg', 'lille', 'montpellier'];
if (targetCities.includes(data.city?.toLowerCase())) {
  score += 20;
} else {
  score += 5;
}

// Critère 2 : Type d'acte (max 25 points)
const premiumActs = ['chirurgie', 'implants', 'liposuccion', 'rhinoplastie'];
const midActs = ['injections', 'botox', 'acide hyaluronique', 'laser'];
if (premiumActs.some(act => data.treatment?.toLowerCase().includes(act))) {
  score += 25;
} else if (midActs.some(act => data.treatment?.toLowerCase().includes(act))) {
  score += 15;
} else {
  score += 5;
}

// Critère 3 : Budget confirmé (max 20 points)
if (data.budget === 'oui' || data.budget === 'yes' || data.budget_range === '> 1000') {
  score += 20;
} else if (data.budget_range === '500-1000') {
  score += 10;
} else {
  score += 5;
}

// Critère 4 : Disponibilité (max 15 points)
if (data.availability === 'cette_semaine' || data.availability === 'this_week') {
  score += 15;
} else if (data.availability === 'ce_mois' || data.availability === 'this_month') {
  score += 10;
} else {
  score += 5;
}

// Critère 5 : Source (max 20 points)
if (data.source === 'meta_ads') {
  score += 20;
} else if (data.source === 'google') {
  score += 15;
} else {
  score += 10;
}

// Classification
let category;
if (score >= 70) {
  category = 'HOT';
} else if (score >= 50) {
  category = 'WARM';
} else {
  category = 'COLD';
}

return {
  ...data,
  lead_score: score,
  lead_category: category,
  scored_at: new Date().toISOString()
};

